"""Utilitaires pour l'écriture des scripts."""

import sys

from docopt import DocoptExit
from docopt import docopt as _docopt

from .command import check_available as _check_available
from .error import Error
from .print import print_error
from .status import STATUS


def docopt(*args, **kwargs) -> None:
    """Wrapper pour *docopt* qui gère les exception DocoptExit.


    Le message est affiché sur la sortie d'erreur et le script est terminé avec
    STATUS.USAGE.
    """
    try:
        return _docopt(*args, **kwargs)
    except DocoptExit as e:
        print(e, file=sys.stderr)
        sys.exit(STATUS.USAGE)


def check_available(*args: str) -> None:
    """Vérifie la disponibilités des exécutables.

    Utilise my.command.check_available pour rechercher les exécutables.
    Lorsque un exécutable est introuvable et qu'une exception est levée, le
    programme est terminé avec une erreur.

    Voir my.command.check_available().
    Voir exit_error().
    """
    try:
        _check_available(*args)
    except Error as e:
        handle_error(e)


def exit_error(message: str, status: int = STATUS.FAILURE) -> None:
    """Termine le script après une erreur.

    Le message est affiché sur la sortie d'erreur et le script est terminé avec
    le status spécifié.
    """
    print_error(message)
    sys.exit(status)


def handle_error(error: Error) -> None:
    """Termine le script après une exception.

    Le message et le status contenus dans l'exception sont passés à
    *exit_error*.

    Voir exit_error().
    """
    exit_error(f"{error.message}", error.status)
